+            const closeFence = '`'.repeat(fenceBacktickCount);
+            const closeIdx = text.indexOf(closeFence, i);
+            if (closeIdx === -1) {
+              result += text.slice(i);
+              i = text.length;
+            } else {
+              result += text.slice(i, closeIdx);
+              i = closeIdx + fenceBacktickCount;
+              fenceBacktickCount = 0;
+              state = SEEKING;
+              buf = '';
